   public String toTraditional(String simplified) {
      StringBuilder result = new StringBuilder();

      for(char c : simplified.toCharArray()) {
         Character traditional = (Character)SIMPLIFIED_TO_TRADITIONAL.get(c);
         result.append(traditional != null ? traditional : c);
      }

      return result.toString();
   }

   public String toSimplified(String traditional) {
      StringBuilder result = new StringBuilder();

      for(char c : traditional.toCharArray()) {
         Character simplified = (Character)TRADITIONAL_TO_SIMPLIFIED.get(c);
         result.append(simplified != null ? simplified : c);
      }

      return result.toString();
   }

   public List<String> convertAllToTraditional(List<String> simplified) {
      List<String> result = new ArrayList();

      for(String s : simplified) {
         result.add(this.toTraditional(s));
      }

      return result;
   }

   public List<String> convertAllToSimplified(List<String> traditional) {
      List<String> result = new ArrayList();

      for(String s : traditional) {
         result.add(this.toSimplified(s));
      }

      return result;
   }

